mapper.select:
SELECT * FROM recharge_records

ORDER BY COALESCE(local_order_time, created_at) DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM recharge_records
WHERE user_id = #{userId}
  AND id != #{excludeId}
  AND local_order_time IS NOT NULL
  AND #{before} IS NOT NULL
  AND local_order_time < #{before}
  AND (
    IFNULL(payment_status,'') IN ('paid','completed')
    OR LOWER(IFNULL(pay_status,'')) IN ('paid','success')
  )
